function scrollSpy(){"use strict";var e=$(window).scrollTop()+window.innerHeight;$('[data-spy="scroll"]').each(function(){var t=$(this),n=t.offset().top,o=e>=n+50;t.toggleClass("in",o)})}function fontScaler(e){"use strict";var t=Math.max(18,Math.round(e.offsetWidth/40));e.style.fontSize=t+"px"}function windowSizer(){"use strict";var e=document.getElementsByClassName("text-scaled"),t=0;for(t=e.length-1;t>=0;t-=1)fontScaler(e[t])}$(document).ready(function(){"use strict";return $("#nav-toggle").on("touchend click",function(){var e=document.getElementById("header").className,t=e.indexOf("in")>=0,n=t?e.replace(" in",""):e+" in";return document.getElementById("header").className=n,!1}),$("html").on("click",function(){$("#header").removeClass("in")}),$('[data-spy="load"]').each(function(){$(this).toggleClass("in")}),$(window).scroll(scrollSpy),scrollSpy(),$(window).resize(windowSizer),!0});